#!/usr/bin/env node
import { execFileSync } from 'node:child_process';
import { appendFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';

const CODEX_BRANCH_PATTERN = /^codex\/issue-(\d+)-/;
const DEFAULT_PUBLIC_WRITE_POLICY = 'after-hours-sgt';
const SGT_OFFSET_MS = 8 * 60 * 60 * 1000;

function notice(message) {
  console.log(`::notice::${message}`);
}

function warning(message) {
  console.log(`::warning::${message}`);
}

function run(command, args, { allowFailure = false } = {}) {
  try {
    return execFileSync(command, args, {
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
      env: process.env,
    }).trim();
  } catch (error) {
    if (allowFailure) return '';
    const stderr = error.stderr?.toString?.().trim();
    const suffix = stderr ? `\n${stderr}` : '';
    throw new Error(`${command} ${args.join(' ')} failed${suffix}`);
  }
}

function gh(args, options) {
  return run('gh', args, options);
}

function git(args, options) {
  return run('git', args, options);
}

function parseJson(raw, fallback) {
  if (!raw || !raw.trim()) return fallback;
  return JSON.parse(raw);
}

export function extractIssueNumberFromBranch(ref = '') {
  return ref.match(CODEX_BRANCH_PATTERN)?.[1] ?? '';
}

export function getIssueBranchPrefix(issueNumber) {
  return `codex/issue-${issueNumber}-`;
}

export function normalizeRemoteBranch(remoteBranch = '') {
  return remoteBranch.trim().replace(/^origin\//, '');
}

export function selectLatestCodexBranch(remoteBranches, issueNumber) {
  const prefix = getIssueBranchPrefix(issueNumber);
  return remoteBranches
    .map(normalizeRemoteBranch)
    .filter((branch) => branch.startsWith(prefix))
    .sort()
    .reverse()[0] ?? '';
}

export function selectIssueNumbersFromCodexBranches(remoteBranches) {
  return [
    ...new Set(
      remoteBranches
        .map(normalizeRemoteBranch)
        .map(extractIssueNumberFromBranch)
        .filter(Boolean)
    ),
  ].sort((a, b) => Number(a) - Number(b));
}

export function isPublicWriteAllowed(policy = DEFAULT_PUBLIC_WRITE_POLICY, at = new Date()) {
  const normalized = String(policy || DEFAULT_PUBLIC_WRITE_POLICY).trim().toLowerCase();
  if (['always', 'allow', 'allowed'].includes(normalized)) return true;
  if (['never', 'off', 'disabled'].includes(normalized)) return false;
  if (!['after-hours-sgt', 'quiet-working-hours-sgt'].includes(normalized)) return true;

  const sgt = new Date(at.getTime() + SGT_OFFSET_MS);
  const day = sgt.getUTCDay();
  const hour = sgt.getUTCHours();
  const isWeekday = day >= 1 && day <= 5;
  return !(isWeekday && hour >= 9 && hour < 18);
}

export function buildPrBody({ issueNumber, branch, ahead }) {
  return [
    `Auto-opened by \`codex.yml\` because a local Codex workflow pushed ${ahead} commits to \`${branch}\` but no PR existed yet.`,
    '',
    `Closes #${issueNumber}.`,
    '',
    'Review checklist:',
    '- CI must pass (typecheck · unit tests · e2e).',
    "- Automated reviewer comment surfaces in the timeline (claude-review acts as Codex's second opinion).",
    '- Read the linked issue and branch commits for the local Codex handoff.',
    '',
    'Generated by codex agent',
  ].join('\n');
}

function sortPrsByUpdatedAt(prs) {
  return [...prs].sort((a, b) => String(b.updatedAt ?? '').localeCompare(String(a.updatedAt ?? '')));
}

function findOpenPrForBranch(branch, ghFn = gh) {
  if (!branch) return undefined;
  const raw = ghFn(['pr', 'list', '--head', branch, '--state', 'open', '--json', 'number,headRefName']);
  return parseJson(raw, [])[0];
}

function findLatestOpenPrForIssue(issueNumber, ghFn = gh) {
  if (!issueNumber) return undefined;
  const prefix = getIssueBranchPrefix(issueNumber);
  const raw = ghFn(['pr', 'list', '--state', 'open', '--json', 'number,headRefName,updatedAt']);
  const prs = parseJson(raw, []);
  return sortPrsByUpdatedAt(prs.filter((pr) => pr.headRefName?.startsWith(prefix)))[0];
}

export function resolveAgentTarget(input, ghFn = gh) {
  const eventName = input.eventName ?? '';
  const issueNumber =
    input.issueNumber ||
    input.pullRequestNumber ||
    extractIssueNumberFromBranch(input.refName) ||
    '';
  const refName = input.refName ?? '';

  if (input.pullRequestHeadRef) {
    return {
      checkoutRef: input.pullRequestHeadRef,
      baseBranch: input.pullRequestHeadRef,
      existingPrBranch: input.pullRequestHeadRef,
      existingPrNumber: input.pullRequestNumber ?? '',
      issueNumber,
    };
  }

  if (input.issueIsPr && input.githubRepository && issueNumber) {
    const pr = parseJson(ghFn(['api', `repos/${input.githubRepository}/pulls/${issueNumber}`]), {});
    const branch = pr.head?.ref ?? '';
    return {
      checkoutRef: branch,
      baseBranch: branch || 'main',
      existingPrBranch: branch,
      existingPrNumber: issueNumber,
      issueNumber,
    };
  }

  if (eventName === 'push' && refName.startsWith('codex/issue-')) {
    const existingPr = findOpenPrForBranch(refName, ghFn);
    return {
      checkoutRef: refName,
      baseBranch: refName,
      existingPrBranch: existingPr?.headRefName ?? '',
      existingPrNumber: existingPr?.number ? String(existingPr.number) : '',
      issueNumber,
    };
  }

  if (issueNumber) {
    const existingPr = findLatestOpenPrForIssue(issueNumber, ghFn);
    if (existingPr) {
      return {
        checkoutRef: existingPr.headRefName,
        baseBranch: existingPr.headRefName,
        existingPrBranch: existingPr.headRefName,
        existingPrNumber: String(existingPr.number),
        issueNumber,
      };
    }
  }

  return {
    checkoutRef: '',
    baseBranch: 'main',
    existingPrBranch: '',
    existingPrNumber: '',
    issueNumber,
  };
}

function writeOutputs(outputs, outputPath = process.env.GITHUB_OUTPUT) {
  if (!outputPath) return;
  const body = Object.entries(outputs)
    .map(([key, value]) => `${key}=${String(value ?? '').replaceAll('\n', '%0A')}`)
    .join('\n');
  appendFileSync(outputPath, `${body}\n`);
}

function resolveTargetFromEnv(env = process.env) {
  return resolveAgentTarget({
    eventName: env.EVENT_NAME,
    githubRepository: env.GH_REPOSITORY || env.GITHUB_REPOSITORY,
    issueNumber: env.ISSUE_NUMBER,
    issueIsPr: env.ISSUE_IS_PR === 'true',
    pullRequestNumber: env.PULL_REQUEST_NUMBER,
    pullRequestHeadRef: env.PULL_REQUEST_HEAD_REF,
    refName: env.REF_NAME || env.GITHUB_REF_NAME,
  });
}

function publicWritesAllowed(env = process.env) {
  const policy = env.AETHER_PUBLIC_WRITE_POLICY || DEFAULT_PUBLIC_WRITE_POLICY;
  if (isPublicWriteAllowed(policy)) return true;
  notice(
    `Public GitHub writes paused by AETHER_PUBLIC_WRITE_POLICY=${policy}; rerun after 18:00 SGT or set the policy to always.`
  );
  return false;
}

function withAuthenticatedOrigin(callback, env = process.env) {
  const repository = env.GH_REPOSITORY || env.GITHUB_REPOSITORY;
  const token = env.GH_TOKEN || env.GITHUB_TOKEN;
  if (!repository || !token) {
    throw new Error('GH_REPOSITORY/GITHUB_REPOSITORY and GH_TOKEN/GITHUB_TOKEN are required for public writes.');
  }
  try {
    git(['remote', 'set-url', 'origin', `https://x-access-token:${token}@github.com/${repository}.git`]);
    return callback();
  } finally {
    git(['remote', 'set-url', 'origin', `https://github.com/${repository}.git`], { allowFailure: true });
  }
}

function dispatchPrChecks(prNumber, branch) {
  if (!prNumber) {
    notice('No PR number resolved; skipping explicit check dispatch.');
    return;
  }
  gh(['workflow', 'run', 'ci.yml', '--ref', branch], { allowFailure: true });
  gh(['workflow', 'run', 'claude-review.yml', '--ref', branch, '-f', `pr_number=${prNumber}`], {
    allowFailure: true,
  });
  notice(`Dispatched CI and reviewer workflows for PR #${prNumber} on ${branch}.`);
}

function refreshExistingPrBranch(env = process.env) {
  const targetBranch = env.TARGET_BRANCH;
  const targetPrNumber = env.TARGET_PR_NUMBER;
  if (!targetBranch) {
    notice('No existing PR branch resolved; skipping refresh.');
    return;
  }
  if (!publicWritesAllowed(env)) return;

  git(['config', 'user.name', 'github-actions[bot]']);
  git(['config', 'user.email', '41898282+github-actions[bot]@users.noreply.github.com']);
  git(['fetch', 'origin', 'main', targetBranch, '--quiet']);
  git(['checkout', '-B', targetBranch, `origin/${targetBranch}`]);
  const before = git(['rev-parse', 'HEAD']);
  try {
    git(['merge', '--no-edit', 'origin/main']);
  } catch {
    git(['merge', '--abort'], { allowFailure: true });
    warning(`Could not auto-merge origin/main into ${targetBranch}; Codex will see the existing PR branch state.`);
    return;
  }
  const after = git(['rev-parse', 'HEAD']);
  if (before !== after) {
    withAuthenticatedOrigin(() => git(['push', 'origin', `HEAD:${targetBranch}`], { allowFailure: false }), env);
    notice(`Merged origin/main into ${targetBranch} before Codex continued.`);
  } else {
    notice(`${targetBranch} already includes origin/main.`);
  }
  dispatchPrChecks(targetPrNumber, targetBranch);
}

function resolveIssueTitle(issueNumber, fallbackTitle) {
  if (fallbackTitle) return fallbackTitle;
  if (!issueNumber) return 'Codex local branch intake';
  const raw = gh(['issue', 'view', String(issueNumber), '--json', 'title'], { allowFailure: true });
  return parseJson(raw, {})?.title ?? `Codex work for issue #${issueNumber}`;
}

function latestRemoteCodexBranch(issueNumber) {
  const raw = git(['branch', '-r', '--list', `origin/${getIssueBranchPrefix(issueNumber)}*`], {
    allowFailure: true,
  });
  return selectLatestCodexBranch(raw.split('\n'), issueNumber);
}

function remoteCodexIssueNumbers() {
  const raw = git(['branch', '-r', '--list', 'origin/codex/issue-*'], {
    allowFailure: true,
  });
  return selectIssueNumbersFromCodexBranches(raw.split('\n'));
}

function openPrForPushedCodexBranch(env = process.env) {
  const issueNumber =
    env.ISSUE_NUMBER ||
    extractIssueNumberFromBranch(env.REF_NAME || env.GITHUB_REF_NAME) ||
    extractIssueNumberFromBranch(env.EXISTING_PR_BRANCH) ||
    '';
  if (!issueNumber) {
    warning('No issue number resolved for Codex branch intake; skipping PR creation.');
    return;
  }
  if (!publicWritesAllowed(env)) return;

  git(['fetch', 'origin', '--prune', '--quiet']);
  const branch = latestRemoteCodexBranch(issueNumber);
  if (!branch) {
    notice(`No ${getIssueBranchPrefix(issueNumber)}* branch on origin; nothing to PR.`);
    return;
  }

  const existingPr = env.EXISTING_PR_BRANCH
    ? {
        headRefName: env.EXISTING_PR_BRANCH,
        number: env.EXISTING_PR_NUMBER,
      }
    : findLatestOpenPrForIssue(issueNumber);
  const existingPrBranch = existingPr?.headRefName ?? '';
  const existingPrNumber = existingPr?.number ? String(existingPr.number) : '';

  if (existingPrBranch) {
    if (branch === existingPrBranch) {
      notice(`Existing PR branch ${existingPrBranch} was the latest agent branch.`);
      return;
    }

    git(['checkout', '-B', existingPrBranch, `origin/${existingPrBranch}`]);
    try {
      git(['merge', '--ff-only', `origin/${branch}`]);
    } catch {
      warning(`Latest codex branch ${branch} did not fast-forward ${existingPrBranch}; leaving it for explicit follow-up.`);
      return;
    }
    withAuthenticatedOrigin(() => git(['push', 'origin', `HEAD:${existingPrBranch}`]), env);
    if (existingPrNumber) {
      gh([
        'pr',
        'comment',
        existingPrNumber,
        '--body',
        `Merged follow-up codex branch \`${branch}\` back into existing PR branch \`${existingPrBranch}\`.`,
      ]);
      dispatchPrChecks(existingPrNumber, existingPrBranch);
    }
    notice(`Merged ${branch} into existing PR branch ${existingPrBranch}.`);
    return;
  }

  const ahead = Number(git(['rev-list', '--count', `origin/main..origin/${branch}`]));
  if (ahead === 0) {
    notice(`Branch ${branch} has 0 commits ahead of main; nothing to PR.`);
    return;
  }
  if (findOpenPrForBranch(branch)) {
    notice(`PR already open for ${branch}.`);
    return;
  }

  const issueTitle = resolveIssueTitle(issueNumber, env.ISSUE_TITLE);
  gh([
    'pr',
    'create',
    '--title',
    issueTitle,
    '--body',
    buildPrBody({ issueNumber, branch, ahead }),
    '--base',
    'main',
    '--head',
    branch,
  ]);
}

function drainQueuedCodexBranches(env = process.env) {
  if (!publicWritesAllowed(env)) return;
  git(['fetch', 'origin', '--prune', '--quiet']);
  const issueNumbers = env.ISSUE_NUMBER ? [env.ISSUE_NUMBER] : remoteCodexIssueNumbers();
  if (issueNumbers.length === 0) {
    notice('No queued codex/issue-* branches found.');
    return;
  }
  for (const issueNumber of issueNumbers) {
    openPrForPushedCodexBranch({ ...env, ISSUE_NUMBER: issueNumber });
    dispatchFreshCodexPr({ ...env, ISSUE_NUMBER: issueNumber });
  }
}

function dispatchFreshCodexPr(env = process.env) {
  const issueNumber =
    env.ISSUE_NUMBER ||
    extractIssueNumberFromBranch(env.REF_NAME || env.GITHUB_REF_NAME) ||
    '';
  if (!issueNumber) {
    warning('No issue number resolved for Codex check dispatch.');
    return;
  }
  if (!publicWritesAllowed(env)) return;

  const pr = findLatestOpenPrForIssue(issueNumber);
  if (!pr) {
    notice(`No open PR for issue #${issueNumber}; nothing to dispatch.`);
    return;
  }
  notice(`Dispatching ci.yml + claude-review.yml for codex PR #${pr.number} on ${pr.headRefName}`);
  dispatchPrChecks(pr.number, pr.headRefName);
}

function logLocalIntake(env = process.env) {
  const issueNumber =
    env.ISSUE_NUMBER ||
    extractIssueNumberFromBranch(env.REF_NAME || env.GITHUB_REF_NAME) ||
    '<n>';
  if (env.EXISTING_PR_BRANCH) {
    notice(`Existing Codex PR branch ${env.EXISTING_PR_BRANCH} is ready for refresh/check dispatch.`);
  } else {
    notice(`No remote agent is running. Waiting for a local Codex push matching codex/issue-${issueNumber}-*.`);
  }
}

function main() {
  const mode = process.env.LOCAL_CODEX_INTAKE_MODE || process.argv[2];
  if (mode === 'resolve') {
    const result = resolveTargetFromEnv();
    writeOutputs({
      checkout_ref: result.checkoutRef,
      base_branch: result.baseBranch,
      existing_pr_branch: result.existingPrBranch,
      existing_pr_number: result.existingPrNumber,
      issue_number: result.issueNumber,
    });
    if (result.checkoutRef) {
      notice(`Codex target branch resolved to ${result.checkoutRef}`);
    } else {
      notice('No existing PR branch found; Codex will start from the event ref.');
    }
    return;
  }
  if (mode === 'refresh') return refreshExistingPrBranch();
  if (mode === 'intake') return logLocalIntake();
  if (mode === 'open-pr') return openPrForPushedCodexBranch();
  if (mode === 'dispatch') return dispatchFreshCodexPr();
  if (mode === 'drain') return drainQueuedCodexBranches();
  throw new Error(`Unknown LOCAL_CODEX_INTAKE_MODE: ${mode}`);
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  try {
    main();
  } catch (error) {
    console.error(error);
    process.exitCode = 1;
  }
}
